 8→void ALFPTurnGameMode::StartPlay()
 9→{
10→    // 从 GameInstance 读取战斗请求
11→    if (ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance()))
12→    {
13→        CachedBattleRequest = GI->ConsumeBattleRequest();
14→        if (CachedBattleRequest.bIsValid)
15→        {
16→            UE_LOG(LogTemp, Log, TEXT("战斗模式: 由世界地图触发，节点 %d, 地图 %s, 星级 %d"),
17→                CachedBattleRequest.SourceNodeID,
18→                *CachedBattleRequest.BattleMapName,
19→                CachedBattleRequest.StarRating);
20→        }
21→    }
22→
23→    // 生成回合管理器
24→    FActorSpawnParameters SpawnParams;
25→    SpawnParams.Owner = this;
26→
27→    ALFPTurnManager* TurnManager = GetWorld()->SpawnActor<ALFPTurnManager>(
28→        ALFPTurnManager::StaticClass(),
29→        FVector::ZeroVector,
30→        FRotator::ZeroRotator,
31→        SpawnParams
32→    );
33→
34→    if (TurnManager)
35→    {
36→        TurnManager->StartGame();
37→    }
38→
39→    Super::StartPlay();
40→
41→    // TODO: 如果有 BattleMapName，让 HexGridManager 加载对应 CSV
42→    // 这需要在 HexGridManager 生成后调用 LoadMapFromCSV
43→}
44→
45→void ALFPTurnGameMode::EndBattle(bool bVictory, bool bEscaped)
46→{
47→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
48→    if (!GI) return;
49→
50→    // 写回战斗结果
51→    FLFPBattleResult Result;
52→    Result.SourceNodeID = CachedBattleRequest.SourceNodeID;
53→    Result.bVictory = bVictory;
54→    Result.bEscaped = bEscaped;
55→    GI->SetBattleResult(Result);
56→
57→    // 返回世界地图
58→    if (CachedBattleRequest.bIsValid)
59→    {
60→        GI->TransitionToWorldMap(TEXT(""));
61→    }
62→}
