  8→void ALFPWorldMapGameMode::StartPlay()
  9→{
 10→	Super::StartPlay();
 11→
 12→	// 生成世界地图管理器
 13→	if (!WorldMapManagerClass)
 14→	{
 15→		UE_LOG(LogTemp, Warning, TEXT("WorldMapManagerClass 未配置"));
 16→		return;
 17→	}
 18→
 19→	FActorSpawnParameters SpawnParams;
 20→	SpawnParams.Owner = this;
 21→	WorldMapManager = GetWorld()->SpawnActor<ALFPWorldMapManager>(
 22→		WorldMapManagerClass, FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
 23→
 24→	if (!WorldMapManager)
 25→	{
 26→		UE_LOG(LogTemp, Error, TEXT("世界地图管理器生成失败"));
 27→		return;
 28→	}
 29→
 30→	UE_LOG(LogTemp, Log, TEXT("世界地图管理器已生成"));
 31→
 32→	// 从 GameInstance 获取状态
 33→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 34→	if (GI && GI->GetWorldMapSnapshot().bIsValid)
 35→	{
 36→		// 从快照恢复
 37→		const FLFPWorldMapSnapshot& Snapshot = GI->GetWorldMapSnapshot();
 38→		UE_LOG(LogTemp, Log, TEXT("从快照恢复世界地图: %s, 节点 %d, 回合 %d"),
 39→			*Snapshot.WorldMapName, Snapshot.CurrentNodeID, Snapshot.CurrentTurn);
 40→
 41→		// 加载地图
 42→		WorldMapManager->LoadWorldMap(Snapshot.WorldMapName);
 43→
 44→		// 恢复玩家状态
 45→		WorldMapManager->InitializePlayer(Snapshot.CurrentNodeID);
 46→		if (ULFPWorldMapPlayerState* PS = WorldMapManager->GetPlayerState())
 47→		{
 48→			PS->CurrentTurn = Snapshot.CurrentTurn;
 49→			PS->VisitedNodeIDs = Snapshot.VisitedNodeIDs;
 50→			PS->RevealedNodeIDs = Snapshot.RevealedNodeIDs;
 51→		}
 52→
 53→		// 恢复已触发节点
 54→		WorldMapManager->RestoreTriggeredNodes(Snapshot.TriggeredNodeIDs);
 55→
 56→		// 更新迷雾
 57→		WorldMapManager->UpdateFog();
 58→
 59→		// 处理战斗结果
 60→		if (GI->HasPendingBattleResult())
 61→		{
 62→			FLFPBattleResult Result = GI->ConsumeBattleResult();
 63→			HandleBattleResult(Result);
 64→		}
 65→	}
 66→	else if (!DefaultWorldMapName.IsEmpty())
 67→	{
 68→		// 首次进入：加载默认地图
 69→		UE_LOG(LogTemp, Log, TEXT("首次进入世界地图: %s"), *DefaultWorldMapName);
 70→		WorldMapManager->LoadWorldMap(DefaultWorldMapName);
 71→		WorldMapManager->InitializePlayer(DefaultStartNodeID);
 72→	}
 73→	else
 74→	{
 75→		// 没有地图可加载（编辑器模式或测试）
 76→		UE_LOG(LogTemp, Log, TEXT("无地图配置，空世界地图"));
 77→	}
 78→}
 79→
 80→void ALFPWorldMapGameMode::HandleBattleResult(const FLFPBattleResult& Result)
 81→{
 82→	if (!WorldMapManager) return;
 83→
 84→	UE_LOG(LogTemp, Log, TEXT("处理战斗结果: 节点 %d, 胜利=%s, 逃跑=%s"),
 85→		Result.SourceNodeID,
 86→		Result.bVictory ? TEXT("是") : TEXT("否"),
 87→		Result.bEscaped ? TEXT("是") : TEXT("否"));
 88→
 89→	if (Result.bVictory)
 90→	{
 91→		// 胜利：节点标记为已触发（如果尚未标记）
 92→		ALFPWorldMapNode* Node = WorldMapManager->GetNode(Result.SourceNodeID);
 93→		if (Node && !Node->bHasBeenTriggered)
 94→		{
 95→			Node->bHasBeenTriggered = true;
 96→			Node->UpdateVisualState();
 97→		}
 98→	}
 99→	else if (Result.bEscaped)
100→	{
101→		// 逃跑：不标记为已触发，可再次进入
102→		UE_LOG(LogTemp, Log, TEXT("逃跑：节点 %d 未标记为已触发"), Result.SourceNodeID);
103→	}
104→	else
105→	{
106→		// 失败：根据游戏设计决定处理方式
107→		// TODO: 游戏结束 or 惩罚后继续
108→		UE_LOG(LogTemp, Warning, TEXT("战斗失败：节点 %d"), Result.SourceNodeID);
109→	}
110→}
