 61→void ALFPTacticsUnit::BeginPlay()
 62→{
 63→    Super::BeginPlay();
 64→
 65→    // 注册到回合管理器
 66→    if (ALFPTurnManager* TurnManager = GetTurnManager())
 67→    {
 68→        TurnManager->RegisterUnit(this);
 69→    }
 70→
 71→    for (ULFPBetrayalCondition* Condition : BetrayalConditions)
 72→    {
 73→        if (Condition)
 74→        {
 75→            Condition->RegisterCondition(this);
 76→        }
 77→    }
 78→
 79→    FLFPHexCoordinates SpawnPoint = FLFPHexCoordinates(StartCoordinates_Q, StartCoordinates_R);
 80→    SetCurrentCoordinates(SpawnPoint);
 81→
 82→	// 初始化血量
 83→    CurrentHealth = MaxHealth;
 84→	InitializeHealthBar();
 85→
 86→    PlannedSkillIconComponent->SetRelativeLocation(FVector(0, SkillIconTopDist, 0)); // 在血条上方
 87→
 88→    // 设置移动时间线
 89→    if (MoveCurve)
 90→    {
 91→        FOnTimelineFloat TimelineCallback;
 92→        TimelineCallback.BindUFunction(this, FName("UpdateMoveAnimation"));
 93→        //MoveTimeline->AddInterpFloat(MoveCurve, TimelineCallback);
 94→
 95→        FOnTimelineEvent TimelineFinishedCallback;
 96→        TimelineFinishedCallback.BindUFunction(this, FName("FinishMove"));
 97→        //MoveTimeline->SetTimelineFinishedFunc(TimelineFinishedCallback);
 98→    }
 99→
100→    // 如果是敌方单位，创建AI控制器
101→    if (IsEnemy())
102→    {
103→        FActorSpawnParameters SpawnParams;
104→        SpawnParams.Owner = this;
105→        SpawnParams.SpawnCollisionHandlingOverride = ESpawnActorCollisionHandlingMethod::AlwaysSpawn;
106→
107→        if (AIControllerClass)
108→        {
109→            AIController = GetWorld()->SpawnActor<ALFPAIController>(AIControllerClass, SpawnParams);
110→            if (AIController)
111→            {
112→                AIController->Possess(this);
113→                AIController->SetControlledUnit(this);
114→            }
115→        }
116→    }
117→}
