119→void ALFPTacticsUnit::EndPlay(const EEndPlayReason::Type EndPlayReason)
120→{
121→    Super::EndPlay(EndPlayReason);
122→
123→    if (ALFPTurnManager* TurnManager = GetTurnManager())
124→    {
125→        TurnManager->UnregisterUnit(this);
126→    }
127→
128→	for (ULFPBetrayalCondition* Condition : BetrayalConditions)
129→	{
130→		if (Condition)
131→		{
132→			Condition->UnRegisterCondition(this);
133→		}
