620→ALFPTacticsUnit* ALFPTacticsUnit::FindBestTarget()
621→{
622→    // 获取所有玩家单位
623→    TArray<AActor*> PlayerUnits;
624→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
625→
626→    ALFPTacticsUnit* BestTarget = nullptr;
627→    float BestThreatValue = -MAX_FLT;
628→
629→    for (AActor* Actor : PlayerUnits)
630→    {
631→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
632→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
633→        {
634→            float ThreatValue = CalculateThreatValue(Unit);
635→            if (ThreatValue > BestThreatValue)
636→            {
637→                BestThreatValue = ThreatValue;
638→                BestTarget = Unit;
639→            }
640→        }
641→    }
642→
643→    return BestTarget;
644→}
