646→ALFPHexTile* ALFPTacticsUnit::FindBestMovementTile(ALFPTacticsUnit* Target)
647→{
648→    ALFPHexGridManager* GridManager = GetGridManager();
649→    if (!GridManager)
650→    {
651→        return nullptr;
652→    }
653→    // 获取所有可移动位置
654→    MovementRangeTiles = GridManager->GetTilesInRange(GetCurrentTile(), GetCurrentMovePoints());
655→
656→    ALFPHexTile* BestTile = nullptr;
657→    float BestPositionValue = -MAX_FLT;
658→
659→    for (ALFPHexTile* Tile : MovementRangeTiles)
660→    {
661→        // 跳过有单位的格子
662→        if (Tile->GetUnitOnTile()) continue;
663→
664→        float PositionValue = CalculatePositionValue(Tile, Target);
665→        if (PositionValue > BestPositionValue)
666→        {
667→            BestPositionValue = PositionValue;
668→            BestTile = Tile;
669→        }
670→    }
671→
672→    return BestTile;
673→}
