 50→void ALFPTurnManager::BeginNewRound()
 51→{
 52→    CurrentRound++;
 53→    bIsInRound = true;
 54→
 55→    // 重置所有单位
 56→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
 57→    {
 58→        if (Unit && Unit->IsValidLowLevel())
 59→        {
 60→            Unit->ResetForNewRound();
 61→        }
 62→    }
 63→
 64→    // 按速度排序单位
 65→    SortUnitsBySpeed();
 66→
 67→    // 清空上一轮的敌人计划
 68→    EnemyActionPlans.Empty();
 69→    AllocatedSkills.Empty();
 70→
 71→    // 恢复阵营 AP
 72→    for (auto& Pair : FactionCurrentAP)
 73→    {
 74→        Pair.Value = FMath::Min(Pair.Value + FactionAPRecovery, FactionMaxAP);
 75→        OnFactionAPChanged.Broadcast(Pair.Key, Pair.Value);
 76→    }
 77→
 78→    // 进入敌人规划阶段
 79→    BeginEnemyPlanningPhase();
 80→}
