119→// ==== 敌人规划阶段 ====
120→
121→void ALFPTurnManager::BeginEnemyPlanningPhase()
122→{
123→    SetPhase(EBattlePhase::BP_EnemyPlanning);
124→
125→    // 过滤出存活的敌方单位，按速度排序
126→    PlanningOrderEnemies.Empty();
127→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
128→    {
129→        if (Unit && Unit->IsAlive() && Unit->IsEnemy())
130→        {
131→            PlanningOrderEnemies.Add(Unit);
132→        }
133→    }
134→
135→    // 敌方单位已按速度排序（继承自 TurnOrderUnits 的排序）
136→
137→    CurrentPlanningEnemyIndex = 0;
138→
139→    if (PlanningOrderEnemies.Num() == 0)
140→    {
141→        // 没有敌方单位，直接进入行动阶段
142→        EndEnemyPlanningPhase();
143→        return;
144→    }
145→
146→    // 隐藏玩家技能选择UI
147→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
148→    {
149→        PC->HideSkillSelection();
150→    }
151→
152→    // Step 1: 全局技能分配（按优先级分配AP技能）
153→    AllocateEnemySkills();
154→
155→    // Step 2: 按速度顺序移动展示
156→    ProcessNextEnemyPlan();
157→}
158→
159→void ALFPTurnManager::ProcessNextEnemyPlan()
160→{
161→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
162→    {
163→        // 所有敌人规划完毕
164→        EndEnemyPlanningPhase();
165→        return;
166→    }
167→
168→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
169→
170→    // 跳过死亡单位
171→    if (!Enemy || !Enemy->IsAlive())
172→    {
173→        CurrentPlanningEnemyIndex++;
174→        ProcessNextEnemyPlan();
175→        return;
176→    }
177→
178→    ALFPAIController* AIController = Enemy->GetAIController();
179→    if (!AIController)
180→    {
181→        CurrentPlanningEnemyIndex++;
182→        ProcessNextEnemyPlan();
183→        return;
184→    }
185→
186→    // 创建行动计划，传入预分配的技能
187→    ULFPSkillBase* PreAllocatedSkill = nullptr;
188→    if (ULFPSkillBase** Found = AllocatedSkills.Find(Enemy))
189→    {
190→        PreAllocatedSkill = *Found;
191→    }
192→    FEnemyActionPlan Plan = AIController->CreateActionPlan(PreAllocatedSkill);
193→
194→    // 存储计划
195→    EnemyActionPlans.Add(Plan);
196→    Enemy->SetActionPlan(Plan);
197→
198→    // 推进到下一个敌人，加延时让玩家观察
199→    CurrentPlanningEnemyIndex++;
200→    FTimerHandle TimerHandle;
201→    GetWorld()->GetTimerManager().SetTimer(
202→        TimerHandle,
203→        this,
204→        &ALFPTurnManager::ProcessNextEnemyPlan,
205→        0.5f,
206→        false
207→    );
208→}
209→
210→void ALFPTurnManager::EndEnemyPlanningPhase()
211→{
212→    BeginActionPhase();
213→}
