215→// ==== 行动阶段 ====
216→
217→void ALFPTurnManager::BeginActionPhase()
218→{
219→    SetPhase(EBattlePhase::BP_ActionPhase);
220→
221→    // 开始第一个单位的回合
222→    if (TurnOrderUnits.Num() > 0)
223→    {
224→        BeginUnitTurn(TurnOrderUnits[0]);
225→    }
226→}
