228→void ALFPTurnManager::BeginUnitTurn(ALFPTacticsUnit* Unit)
229→{
230→    OnTurnChanged.Broadcast();
231→
232→    CurrentUnit = Unit;
233→
234→    ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>();
235→
236→    // 敌方单位在行动阶段：执行预定计划
237→    if (Unit->IsEnemy() && CurrentPhase == EBattlePhase::BP_ActionPhase)
238→    {
239→        if (PC)
240→        {
241→            PC->HideSkillSelection();
242→        }
243→
244→        Unit->OnTurnStarted();
245→
246→        ExecuteEnemyPlan(Unit);
247→        return;
248→    }
249→
250→    // 玩家单位：保持原有逻辑
251→    if (Unit)
252→    {
253→        Unit->OnTurnStarted();
254→    }
255→
256→    if (PC)
257→    {
258→        PC->OnTurnStarted(Unit);
259→        PC->SelectUnit(Unit);
260→        PC->HandleSkillSelection();
261→    }
262→}
