264→void ALFPTurnManager::ExecuteEnemyPlan(ALFPTacticsUnit* Unit)
265→{
266→    const FEnemyActionPlan& Plan = GetPlanForEnemy(Unit);
267→
268→    if (Plan.bIsValid && Plan.PlannedSkill)
269→    {
270→        // 在原定目标格子释放技能（即使目标已死亡）
271→        // AP 已在规划阶段 AllocateEnemySkills 中扣除
272→        Unit->ExecuteSkill(Plan.PlannedSkill, Plan.TargetTile);
273→    }
274→
275→    // 清除头顶技能图标
276→    Unit->ClearActionPlan();
277→
278→    // 短延时后结束回合（让玩家看到技能效果）
279→    FTimerHandle TimerHandle;
280→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this, Unit]()
281→    {
282→        Unit->SetHasActed(true);
283→        PassTurn();
284→    }, 0.5f, false);
285→}
286→
287→void ALFPTurnManager::EndUnitTurn(ALFPTacticsUnit* Unit)
288→{
289→    if (Unit)
290→    {
291→        Unit->OnTurnEnded();
292→    }
293→
294→    // 通知玩家控制器
295→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
296→    {
297→        PC->OnTurnEnded(Unit);
298→    }
299→}
300→
301→void ALFPTurnManager::PassTurn()
302→{
303→    if (!CurrentUnit || TurnOrderUnits.IsEmpty())
304→    {
305→        return;
306→    }
307→
308→    // 结束当前单位回合
309→    EndUnitTurn(CurrentUnit);
310→
311→    // 找到下一个未行动的单位
312→    int32 CurrentIndex = TurnOrderUnits.Find(CurrentUnit);
313→    int32 NextIndex = (CurrentIndex + 1) % TurnOrderUnits.Num();
314→
315→    // 检查所有单位是否行动完毕
316→    bool TurnOrderUnitsActed = true;
317→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
318→    {
319→        if (Unit && Unit->IsAlive() && !Unit->HasActed())
320→        {
321→            TurnOrderUnitsActed = false;
322→            break;
323→        }
324→    }
325→
326→    if (TurnOrderUnitsActed)
327→    {
328→        // 所有单位行动完毕，结束回合
329→        EndCurrentRound();
330→    }
331→    else
332→    {
333→        // 寻找下一个未行动单位
334→        for (int32 i = 0; i < TurnOrderUnits.Num(); i++)
335→        {
336→            int32 Index = (NextIndex + i) % TurnOrderUnits.Num();
337→            ALFPTacticsUnit* NextUnit = TurnOrderUnits[Index];
338→
339→            if (NextUnit && NextUnit->IsAlive() && !NextUnit->HasActed())
340→            {
341→                BeginUnitTurn(NextUnit);
342→                return;
343→            }
344→        }
345→
346→        // 没有找到未行动单位，结束回合
347→        EndCurrentRound();
348→    }
349→}
