414→
415→void ALFPTurnManager::ConsumeFactionAP(EUnitAffiliation Faction, int32 Amount)
416→{
417→    if (int32* AP = FactionCurrentAP.Find(Faction))
418→    {
419→        *AP = FMath::Max(0, *AP - Amount);
420→        OnFactionAPChanged.Broadcast(Faction, *AP);
421→    }
422→}
423→
424→// ==== 全局技能分配 ====
425→
426→void ALFPTurnManager::AllocateEnemySkills()
427→{
428→    AllocatedSkills.Empty();
429→
430→    // 收集所有敌方单位的所有消耗AP的技能候选
431→    struct FSkillCandidate
432→    {
433→        ALFPTacticsUnit* Unit;
434→        ULFPSkillBase* Skill;
435→        float EffectivePriority;
436→    };
437→    TArray<FSkillCandidate> Candidates;
438→
439→    for (ALFPTacticsUnit* Enemy : PlanningOrderEnemies)
440→    {
441→        if (!Enemy || !Enemy->IsAlive()) continue;
442→
443→        TArray<ULFPSkillBase*> Skills = Enemy->GetAvailableSkills();
444→        for (ULFPSkillBase* Skill : Skills)
445→        {
446→            if (!Skill) continue;
447→            if (Skill->ActionPointCost <= 0) continue; // 0消耗技能不参与竞争
448→            if (Skill->CurrentCooldown > 0) continue;  // 冷却中跳过
449→
450→            FSkillCandidate Candidate;
451→            Candidate.Unit = Enemy;
452→            Candidate.Skill = Skill;
453→            Candidate.EffectivePriority = Skill->GetEffectivePriority();
454→            Candidates.Add(Candidate);
455→        }
456→    }
457→
458→    // 按有效优先级降序排序
459→    Candidates.Sort([](const FSkillCandidate& A, const FSkillCandidate& B) {
460→        return A.EffectivePriority > B.EffectivePriority;
461→    });
462→
463→    // 依次分配：如果阵营AP足够且该单位尚未分配
464→    for (const FSkillCandidate& Candidate : Candidates)
465→    {
466→        // 该单位已分配过技能，跳过
467→        if (AllocatedSkills.Contains(Candidate.Unit)) continue;
468→
469→        // 检查阵营AP是否足够
470→        if (HasEnoughFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost))
471→        {
472→            AllocatedSkills.Add(Candidate.Unit, Candidate.Skill);
473→            ConsumeFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost);
474→        }
475→    }
476→
477→    // 未分配到AP技能的敌人会在 CreateActionPlan 中 fallback 到默认攻击
478→}
