I now have a comprehensive understanding of the codebase. Let me produce the implementation plan.

---

## Implementation Plan: Party & Reserve Roster System

### Overview

This plan adds a lightweight party/reserve roster system that persists across level transitions via `ULFPGameInstance`. It covers 7 areas: the unit entry struct, a unit registry data asset, party/reserve storage on GameInstance, battle result modification for captured units, battle-side capture tracking, post-battle processing on the world map, and a replacement UI widget.

---

### 1. FLFPUnitEntry Struct (new, in LFPGameInstance.h)

Add this struct **above** the `FLFPBattleRequest` definition in `d:\UE_Projects\LFP2D\Source\LFP2D\Core\LFPGameInstance.h`. Placing it here keeps all cross-level data transfer types in one header that both battle and world map code already include.

```cpp
// 轻量单位数据：跨关卡保存用
USTRUCT(BlueprintType)
struct FLFPUnitEntry
{
    GENERATED_BODY()

    // 单位类型 ID（对应 ULFPUnitRegistryDataAsset 中的键）
    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Unit")
    FName TypeID = NAME_None;

    // 单位星级/等级
    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Unit")
    int32 Tier = 1;

    bool IsValid() const { return TypeID != NAME_None; }
};
```

**Design decision**: No HP persistence. Each battle starts at full HP, so `FLFPUnitEntry` only stores identity + progression tier. This is intentionally minimal.

---

### 2. ULFPUnitRegistryDataAsset (new file)

**New file**: `d:\UE_Projects\LFP2D\Source\LFP2D\Core\LFPUnitRegistryDataAsset.h`

This is a single global DataAsset (created in Content Browser, configured once) that maps TypeID to blueprint class, display name, and icon. Follows the same pattern as `ULFPWorldNodeDataAsset` and `ULFPSkillDataAsset`.

```cpp
#pragma once

#include "CoreMinimal.h"
#include "Engine/DataAsset.h"
#include "LFPUnitRegistryDataAsset.generated.h"

class ALFPTacticsUnit;

// 单位注册表条目
USTRUCT(BlueprintType)
struct FLFPUnitRegistryEntry
{
    GENERATED_BODY()

    // 单位蓝图类
    UPROPERTY(EditAnywhere, BlueprintReadOnly, Category = "Unit Registry")
    TSubclassOf<ALFPTacticsUnit> UnitClass;

    // 显示名称
    UPROPERTY(EditAnywhere, BlueprintReadOnly, Category = "Unit Registry")
    FText DisplayName;

    // 单位图标（UI 用）
    UPROPERTY(EditAnywhere, BlueprintReadOnly, Category = "Unit Registry")
    TObjectPtr<UTexture2D> Icon = nullptr;
};

/**
 * 单位注册表：全局唯一，映射 TypeID → 单位蓝图类和元数据
 */
UCLASS(Blueprintable)
class LFP2D_API ULFPUnitRegistryDataAsset : public UDataAsset
{
    GENERATED_BODY()

public:
    // TypeID → 单位数据映射
    UPROPERTY(EditAnywhere, BlueprintReadOnly, Category = "Unit Registry")
    TMap<FName, FLFPUnitRegistryEntry> UnitRegistry;

    // 查找条目
    UFUNCTION(BlueprintPure, Category = "Unit Registry")
    bool FindEntry(FName TypeID, FLFPUnitRegistryEntry& OutEntry) const;

    // 获取蓝图类
    UFUNCTION(BlueprintPure, Category = "Unit Registry")
    TSubclassOf<ALFPTacticsUnit> GetUnitClass(FName TypeID) const;
};
```

**No .cpp needed for the class itself** -- `FindEntry` and `GetUnitClass` are trivial lookups that can be inlined or placed in a minimal .cpp:

`d:\UE_Projects\LFP2D\Source\LFP2D\Core\LFPUnitRegistryDataAsset.cpp`:
```cpp
#include "LFP2D/Core/LFPUnitRegistryDataAsset.h"

bool ULFPUnitRegistryDataAsset::FindEntry(FName TypeID, FLFPUnitRegistryEntry& OutEntry) const
{
    if (const FLFPUnitRegistryEntry* Found = UnitRegistry.Find(TypeID))
    {
        OutEntry = *Found;
        return true;
    }
    return false;
}

TSubclassOf<ALFPTacticsUnit> ULFPUnitRegistryDataAsset::GetUnitClass(FName TypeID) const
{
    if (const FLFPUnitRegistryEntry* Found = UnitRegistry.Find(TypeID))
    {
        return Found->UnitClass;
    }
    return nullptr;
}
```

---

### 3. Party/Reserve Storage in GameInstance

**File**: `d:\UE_Projects\LFP2D\Source\LFP2D\Core\LFPGameInstance.h`

Add party and reserve arrays plus management methods to `ULFPGameInstance`. GameInstance survives level transitions, so this is the natural home.

Add to the **public** section of the class:

```cpp
// ============== 编队系统 ==============

// 单位注册表（蓝图中配置，全局唯一）
UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
TObjectPtr<ULFPUnitRegistryDataAsset> UnitRegistry;

// 出战队伍
UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
TArray<FLFPUnitEntry> PartyUnits;

// 后备队伍
UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
TArray<FLFPUnitEntry> ReserveUnits;

// 出战队伍上限（可配置）
UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
int32 MaxPartySize = 3;

// 后备队伍上限（可配置）
UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
int32 MaxReserveSize = 3;

// 尝试添加单位：先编队 → 再后备 → 都满返回 false
UFUNCTION(BlueprintCallable, Category = "Party")
bool TryAddUnit(const FLFPUnitEntry& Unit);

// 编队是否已满
UFUNCTION(BlueprintPure, Category = "Party")
bool IsPartyFull() const { return PartyUnits.Num() >= MaxPartySize; }

// 后备是否已满
UFUNCTION(BlueprintPure, Category = "Party")
bool IsReserveFull() const { return ReserveUnits.Num() >= MaxReserveSize; }

// 替换编队中的单位（替换 UI 调用）
UFUNCTION(BlueprintCallable, Category = "Party")
void ReplacePartyUnit(int32 SlotIndex, const FLFPUnitEntry& NewUnit);

// 替换后备中的单位
UFUNCTION(BlueprintCallable, Category = "Party")
void ReplaceReserveUnit(int32 SlotIndex, const FLFPUnitEntry& NewUnit);

// 移除编队单位
UFUNCTION(BlueprintCallable, Category = "Party")
void RemovePartyUnit(int32 SlotIndex);

// 移除后备单位
UFUNCTION(BlueprintCallable, Category = "Party")
void RemoveReserveUnit(int32 SlotIndex);
```

**Implementation** in `LFPGameInstance.cpp`:

```cpp
bool ULFPGameInstance::TryAddUnit(const FLFPUnitEntry& Unit)
{
    if (!IsPartyFull())
    {
        PartyUnits.Add(Unit);
        return true;
    }
    if (!IsReserveFull())
    {
        ReserveUnits.Add(Unit);
        return true;
    }
    return false;
}

void ULFPGameInstance::ReplacePartyUnit(int32 SlotIndex, const FLFPUnitEntry& NewUnit)
{
    if (PartyUnits.IsValidIndex(SlotIndex))
    {
        PartyUnits[SlotIndex] = NewUnit;
    }
}

void ULFPGameInstance::ReplaceReserveUnit(int32 SlotIndex, const FLFPUnitEntry& NewUnit)
{
    if (ReserveUnits.IsValidIndex(SlotIndex))
    {
        ReserveUnits[SlotIndex] = NewUnit;
    }
}

void ULFPGameInstance::RemovePartyUnit(int32 SlotIndex)
{
    if (PartyUnits.IsValidIndex(SlotIndex))
    {
        PartyUnits.RemoveAt(SlotIndex);
    }
}

void ULFPGameInstance::RemoveReserveUnit(int32 SlotIndex)
{
    if (ReserveUnits.IsValidIndex(SlotIndex))
    {
        ReserveUnits.RemoveAt(SlotIndex);
    }
}
```

Forward declare at the top of the header:
```cpp
class ULFPUnitRegistryDataAsset;
```

And add the include in the .cpp:
